INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('cpa-moex-01800', 'cpa', 'cpa-moex-102-9a386a01', 'sub-cpa-08', NULL, 'single_choice', '曹丕〈與吳質書〉：「昔伯牙絕弦於鍾期，仲尼覆醢於子路，痛知音之難遇，傷門 人之莫逮。諸子但為未及古人，自一時之雋也。今之存者，已不逮矣！後生可畏， 來者難誣。然恐吾與足下不及見也。」 關於此段文字之敘述，下列何者正確？', '["「後生可畏，來者難誣」之「畏」引申有敬佩之意", "「伯牙絕弦於鍾期」的原因是從此無人可以調音，無法再演奏", "「仲尼覆醢於子路」敘述孔子因子路衝動、魯莽，而不願與之共餐", "「然恐吾與足下不及見也」，在感嘆後生晚輩實力無法預測，令人擔憂"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:01+00:00", "source_pdf_sha1": "8601059dd73e", "answer_pdf_sha1": "e76b12d6173c", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01801', 'cpa', 'cpa-moex-102-9a386a01', 'sub-cpa-08', NULL, 'single_choice', '高子病痿，不出內戶者旬月。客散擁榻，目無所寄，則常屬之窗與簾。簾附窗，而 嫟於壁，壁之穴蟲多緣而遊。有蛛初來登簾，若涉大險。簾有界隙，動輒失足，失 足則驚，驚輒退縮不敢前，則惴惴而行，帖帖而蹲，其勢若不終日者已。乃戲令撤 其窗扉，使去壁遠而絕其歸，奪其所安而重困之。意初不堪，久且苦飢，無所食， 則強起而掠簾蠅。一日而坦，二日而躍，三日則投擲如飛矣。 下列文句最接近本文意旨的選項是：', '["置之死地而後生", "業精於勤荒於嬉", "立身行己，居安如墜", "怨人不如自怨，求諸人不如求諸己"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:01+00:00", "source_pdf_sha1": "8601059dd73e", "answer_pdf_sha1": "e76b12d6173c", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01802', 'cpa', 'cpa-moex-102-9a386a01', 'sub-cpa-08', NULL, 'single_choice', '白居易〈杏園中棗樹〉：「人言百果中，唯棗凡且鄙。皮皴似龜手，葉小如鼠耳。 胡為不自知，生花此園裏。……東風不擇木，吹煦長未已。眼看欲合抱，得盡生生 理。寄言遊春客，乞君一迴視。君愛繞指柔，從君憐柳杞。君求悅目豔，不敢爭桃 李。君若作大車，輪軸材須此。」 下列選項，何者最切近本文旨意？', '["強調女為悅己者容", "強調賞心悅目的重要", "強調為人必須表裏一致", "強調物雖或平凡，卻能致用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:01+00:00", "source_pdf_sha1": "8601059dd73e", "answer_pdf_sha1": "e76b12d6173c", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01803', 'cpa', 'cpa-moex-102-9a386a01', 'sub-cpa-08', NULL, 'single_choice', '王守仁〈教條示龍場諸生〉：「責善，朋友之道。然須忠告而善道之，悉其忠愛，致 其婉曲，使彼聞之而可從，繹之而可改，有所感而無所怒，乃為善耳。若先暴白其過 惡，痛毀極詆，使無所容，彼將發其愧恥憤恨之心，雖欲降以相從，而勢有所不能。」 根據上文，下列敘述何者正確？', '["「暴白其過惡，痛毀極詆」有助於責善", "激起朋友的「愧恥憤恨之心」是責善的目的", "「繹之而可改」是有心向善的人難以做到的", "「悉其忠愛，致其婉曲」是理想的責善之道"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:01+00:00", "source_pdf_sha1": "8601059dd73e", "answer_pdf_sha1": "e76b12d6173c", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01804', 'cpa', 'cpa-moex-102-9a386a01', 'sub-cpa-08', NULL, 'single_choice', '「不畏浮雲遮望眼」（王安石〈登飛來峰〉），是對待政治現實的態度。下列詩文 中「浮雲」此一意象所指涉的意義，何者與本句中的「浮雲」相同？', '["雷鼓震地起，猛勢陵浮雲（《宋書．樂志》）", "不義而富且貴，於我如浮雲（《論語．述而》）", "總為浮雲能蔽日，長安不見使人愁（李白〈登金陵鳳凰臺〉）", "從前種種暱愛，如浮雲散滅，都無餘滓（《閱微草堂筆記．灤陽消夏錄》） 孟嘗君逐於齊而復反。譚拾子迎之於境，謂孟嘗君曰：「君得無有所怨齊士大夫？」孟 嘗君曰：「有。」「君滿意殺之乎？」孟嘗君曰：「然。」譚拾子曰：「事有必至，理 有固然，君知之乎？」孟嘗君曰：「不知。」譚拾子曰：「事之必至者，死也；理之固 然者，富貴則就之，貧賤則去之。此事之必至，理之固然者。請以市諭：市，朝則滿， 夕則虛，非朝愛市而夕憎之也。求存故往，亡故去。願君勿怨。」孟嘗君乃取所怨五百 牒削去之，不敢以為言。（《戰國策．齊策》） 請依上文回答第13題至第14題"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:01+00:00", "source_pdf_sha1": "8601059dd73e", "answer_pdf_sha1": "e76b12d6173c", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01805', 'cpa', 'cpa-moex-102-9a386a01', 'sub-cpa-08', NULL, 'single_choice', '文中「孟嘗君逐於齊而復反」，意謂：', '["孟嘗君奔走於齊國企圖再次謀反", "孟嘗君被齊君驅逐以後企圖謀反", "孟嘗君遭齊君罷黜以後又被召回", "孟嘗君到齊國訪求賢才後返回國境"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:01+00:00", "source_pdf_sha1": "8601059dd73e", "answer_pdf_sha1": "e76b12d6173c", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01806', 'cpa', 'cpa-moex-102-9a386a01', 'sub-cpa-08', NULL, 'single_choice', '根據上文敘述，下列選項何者正確？', '["孟嘗君堅持殺齊國士大夫，才能心滿意足", "朝愛市而夕憎之，是因為齊君朝令夕改", "孟嘗君聽從勸告，除去了所怨恨者的名單", "譚拾子勸諫無效後，終身不再對孟嘗君進言"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:01+00:00", "source_pdf_sha1": "8601059dd73e", "answer_pdf_sha1": "e76b12d6173c", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01807', 'cpa', 'cpa-moex-102-9a386a01', 'sub-cpa-08', NULL, 'single_choice', '源遠流長的中華文明中，在竹文化方面的積澱，非常豐厚。中國人，尤其是古代的 中國人，衣、食、住、行等方面，同竹子都有千絲萬縷的關係，因此古人吟詠竹子 的詩文很多。下列各選項，何者不是詠竹的作品？', '["龍吟曾未聽，鳳曲吹應好。不學蒲柳凋，貞心嘗自保", "一節復一節，千枝攢萬葉。我自不開花，免撩蜂與蝶", "一頃含秋綠，森風十萬竿。氣吹朱夏轉，聲掃碧霄寒", "落落出群非櫸柳，青青不朽豈楊梅。欲存老蓋千年意，為覓霜根數寸栽"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:01+00:00", "source_pdf_sha1": "8601059dd73e", "answer_pdf_sha1": "e76b12d6173c", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01808', 'cpa', 'cpa-moex-102-9a386a01', 'sub-cpa-08', NULL, 'single_choice', '西方作家卡爾維諾《為什麼讀經典》說：「我們應該在成年時代撥出一段時間，用 來重新發現年輕時代最重要的閱讀。儘管作品依舊（不過在不同的歷史觀點下， 這些作品也會改變），我們卻一定有所改變，所以與這些作品後來的相遇是全新的經 驗。」 下列敘述何者最切近作者對閱讀的體會？', '["溫故而知新", "學然後知不足", "學而不思則罔，思而不學則殆", "知之者不如好之者，好之者不如樂之者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:01+00:00", "source_pdf_sha1": "8601059dd73e", "answer_pdf_sha1": "e76b12d6173c", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01809', 'cpa', 'cpa-moex-102-9a386a01', 'sub-cpa-08', NULL, 'single_choice', '下列文字節選自林燿德〈終端機〉，詩中空格最適合填入？ ……………………我 迷失在數字的海洋裡 顯示器上 排排浮現 降落中的符號 像是整個世界的幕落 終端機前 我的心神散落成顯示器上的顆粒 終端機內 精密的迴路恰似隱藏智慧的聖櫃 加班之後我漫步在午夜的街頭 那些程式仍然□□□焊插在下意識裡 拔也拔不去 開始懷疑自己體內裝盛的不是□□ 而是一排排的積體電路 下班的我 帶著喪失電源的□□□ 成為一部斷線的終端機', '["慢慢地／電流／水晶體", "漸漸地／骨架／半導體", "狠狠地／血肉／記憶體", "輕輕地／情感／多媒體"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:01+00:00", "source_pdf_sha1": "8601059dd73e", "answer_pdf_sha1": "e76b12d6173c", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
